mapper.select:
SELECT rr.id, rr.backup_id AS backupId, rr.backup_name AS backupName, rr.operator_id AS operatorId, rr.status, rr.remark, rr.created_at AS createdAt, (SELECT au.username FROM admin_users au WHERE au.id = rr.operator_id) AS operatorName FROM restore_records rr
AND rr.status = #{status}
ORDER BY rr.created_at DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE restore_records
SET status = #{status}, remark = #{remark}
WHERE id = #{id}

